// ── FILTER VICTIMS TO OT / ENERGY SECTORS ──────────────────────────
const OT_SECTORS = [
  'energy', 'oil', 'gas', 'electric', 'utilities', 'utility',
  'nuclear', 'pipeline', 'water', 'wastewater', 'power',
  'manufacturing', 'critical manufacturing', 'industrial',
  'chemical', 'mining', 'petrochemical', 'refin', 'grid'
];

const items = $input.all();
const seen = new Set();
const filtered = [];

for (const item of items) {
  const raw = item.json;
  // Handle both array response and single object
  const records = Array.isArray(raw) ? raw : [raw];
  for (const rec of records) {
    if (!rec || typeof rec !== 'object') continue;
    const key = (rec.post_title || rec.name || JSON.stringify(rec)).slice(0, 100);
    if (seen.has(key)) continue;
    seen.add(key);
    const searchText = [
      rec.activity || '', rec.post_title || '',
      rec.country || '', rec.description || '', rec.sector || ''
    ].join(' ').toLowerCase();
    if (OT_SECTORS.some(s => searchText.includes(s))) {
      filtered.push({
        json: {
          source: 'ransomware.live',
          victim_name: rec.post_title || rec.name || 'Unknown',
          group: rec.group_name || rec.group || 'Unknown',
          country: rec.country || 'Unknown',
          sector: rec.activity || rec.sector || 'Unknown',
          website: rec.website || null,
          discovered: rec.discovered || rec.published || null
        }
      });
    }
  }
}

return filtered.slice(0, 80);

// ── PARSE THREAT GROUPS — with 502 / empty fallback ────────────────
const OT_GROUPS = [
  'lockbit', 'blackcat', 'alphv', 'cl0p', 'clop',
  'play', 'akira', 'black basta', 'rhysida', 'hunters',
  'medusa', 'ransomhub', 'qilin', 'dragonforce',
  'volt typhoon', 'bauxite', 'graphite', 'electrum',
  'voltzite', 'sandworm', 'scattered spider'
];

const items = $input.all();
const groups = [], ttps = [], tools = [], iocs = [];
let hasData = false;

for (const item of items) {
  const j = item.json;
  // Detect HTTP errors
  if (j?.error || (j?.statusCode && j.statusCode >= 400)) continue;
  const raw = Array.isArray(j) ? j : (Array.isArray(j?.data) ? j.data : [j]);
  for (const g of raw) {
    if (!g || typeof g !== 'object' || !g.name) continue;
    hasData = true;
    const name = (g.name || '').toLowerCase();
    const isRelevant = OT_GROUPS.some(og => name.includes(og)) || raw.length < 30;
    if (!isRelevant) continue;
    groups.push({ name: g.name, country: g.country || 'Unknown', description: (g.description || '').slice(0, 200) });
    if (Array.isArray(g.ttps)) {
      g.ttps.forEach(t => ttps.push({ group: g.name, tactic: t.tactic || '', technique: t.technique || '', technique_id: t.technique_id || '' }));
    }
    if (g.tools && typeof g.tools === 'object') {
      Object.entries(g.tools).forEach(([cat, list]) => {
        (Array.isArray(list) ? list : [list]).forEach(tool => {
          tools.push({ group: g.name, category: cat, tool: typeof tool === 'string' ? tool : (tool?.name || String(tool)) });
        });
      });
    }
    if (g.btc_address) {
      (Array.isArray(g.btc_address) ? g.btc_address : [g.btc_address])
        .filter(Boolean).forEach(addr => iocs.push({ group: g.name, type: 'btc', value: addr }));
    }
    if (Array.isArray(g.locations)) {
      g.locations.filter(l => l.fqdn).forEach(l => iocs.push({ group: g.name, type: 'domain', value: l.fqdn }));
    }
  }
}

return [{ json: {
  source: 'ransomware.live/groups',
  group_count: groups.length,
  groups: groups.slice(0, 20),
  ttps: ttps.slice(0, 60),
  tools: tools.slice(0, 40),
  group_iocs: iocs.slice(0, 40),
  fetch_note: hasData ? 'OK' : 'Groups endpoint unavailable — workflow continues with empty fallback'
}}];

// ── PARSE CISA KEV — robust response unwrapping ─────────────────────
const ICS_VENDORS = [
  'siemens', 'schneider', 'rockwell', 'allen-bradley', 'honeywell',
  'ge ', 'general electric', 'abb', 'mitsubishi', 'yokogawa',
  'emerson', 'aveva', 'osisoft', 'wonderware', 'inductive automation',
  'beckhoff', 'moxa', 'advantech', 'delta electronics',
  'hitachi', 'phoenix contact', 'wago', 'pilz', 'omron', 'fanuc'
];
const ICS_KEYWORDS = [
  'scada', 'ics', 'plc', 'hmi', 'modbus', 'dnp3', 'opc',
  'historian', 'dcs', 'rtu', 'industrial control', 'control system', 'firmware'
];

const items = $input.all();
let vulns = [];

for (const item of items) {
  const j = item.json;
  if (Array.isArray(j?.vulnerabilities)) { vulns = j.vulnerabilities; break; }
  if (Array.isArray(j)) { vulns = j; break; }
  if (typeof j?.body === 'string') {
    try { const p = JSON.parse(j.body); if (Array.isArray(p?.vulnerabilities)) { vulns = p.vulnerabilities; break; } } catch(e) {}
  }
  // Try all string values in the object
  for (const val of Object.values(j || {})) {
    if (typeof val === 'string' && val.includes('cveID')) {
      try { const p = JSON.parse(val); if (Array.isArray(p?.vulnerabilities)) { vulns = p.vulnerabilities; break; } } catch(e) {}
    }
  }
}

const filtered = vulns.filter(v => {
  const text = [v.vendorProject || '', v.product || '', v.vulnerabilityName || '', v.shortDescription || ''].join(' ').toLowerCase();
  return ICS_VENDORS.some(s => text.includes(s)) || ICS_KEYWORDS.some(s => text.includes(s));
});

filtered.sort((a, b) => new Date(b.dateAdded || 0) - new Date(a.dateAdded || 0));

const recent = filtered.slice(0, 20).map(v => ({
  cve_id: v.cveID || '',
  vendor: v.vendorProject || '',
  product: v.product || '',
  name: v.vulnerabilityName || '',
  description: (v.shortDescription || '').slice(0, 200),
  date_added: v.dateAdded || '',
  due_date: v.dueDate || '',
  ransomware_use: v.knownRansomwareCampaignUse || 'Unknown'
}));

return [{ json: {
  source: 'CISA KEV',
  total_ics_kevs: filtered.length,
  ransomware_used_count: recent.filter(v => v.ransomware_use === 'Known').length,
  recent_kevs: recent,
  fetch_note: vulns.length > 0 ? 'OK' : 'KEV feed returned no data — check fetch node headers'
}}];

// ── PARSE CISA ICS ADVISORIES RSS — robust XML extraction ───────────
const items = $input.all();
let xmlStr = '';

for (const item of items) {
  const j = item.json;
  if (typeof j?.body === 'string' && j.body.includes('<item>'))       { xmlStr = j.body; break; }
  if (typeof j?.data === 'string' && j.data.includes('<item>'))       { xmlStr = j.data; break; }
  if (typeof j === 'string'       && j.includes('<item>'))            { xmlStr = j; break; }
  // Check all string values
  for (const val of Object.values(j || {})) {
    if (typeof val === 'string' && val.includes('<item>')) { xmlStr = val; break; }
  }
  if (xmlStr) break;
}

const OT_KW = [
  'energy', 'scada', 'ics', 'plc', 'hmi', 'industrial', 'power',
  'grid', 'pipeline', 'oil', 'gas', 'electric', 'utility', 'water',
  'nuclear', 'siemens', 'schneider', 'rockwell', 'honeywell',
  'abb', 'aveva', 'modbus', 'dnp3', 'opc', 'historian', 'rtu', 'dcs'
];

let advisories = [];

if (xmlStr) {
  const itemMatches = [...xmlStr.matchAll(/<item>([\s\S]*?)<\/item>/gi)];
  advisories = itemMatches.slice(0, 30).map(m => {
    const block = m[1];
    const getTag = tag => {
      const r = block.match(new RegExp(`<${tag}[^>]*>([\\s\\S]*?)<\\/${tag}>`, 'i'));
      return r ? r[1].replace(/<!\[CDATA\[/g,'').replace(/\]\]>/g,'')
                     .replace(/<[^>]+>/g,'').replace(/&lt;/g,'<')
                     .replace(/&gt;/g,'>').replace(/&amp;/g,'&').trim() : '';
    };
    return {
      title: getTag('title'),
      link: getTag('link'),
      published: getTag('pubDate'),
      summary: getTag('description').slice(0, 300)
    };
  }).filter(a => a.title);

  advisories.forEach(a => {
    const text = (a.title + ' ' + a.summary).toLowerCase();
    a.ot_relevant = OT_KW.some(kw => text.includes(kw));
  });
}

const otRelevant = advisories.filter(a => a.ot_relevant);

return [{ json: {
  source: 'CISA ICS Advisories',
  total_advisories: advisories.length,
  ot_relevant_count: otRelevant.length,
  advisories: advisories,
  ot_advisories: otRelevant,
  fetch_note: xmlStr ? 'OK' : 'RSS feed returned no parseable XML — using empty fallback'
}}];

// ── EXTRACT IOCs FOR ENRICHMENT ─────────────────────────────────────
const items = $input.all();
const iocs = [];

for (const item of items) {
  const v = item.json;
  if (v.website) {
    const domain = v.website
      .replace(/https?:\/\//i, '').split('/')[0].split('?')[0].trim();
    if (domain && domain.includes('.') && !iocs.find(i => i.value === domain)) {
      iocs.push({ type: 'domain', value: domain, victim: v.victim_name, group: v.group });
    }
  }
}

return iocs.slice(0, 10).map(i => ({ json: i }));

// ── ENRICH IOC WITH VT RESULTS ──────────────────────────────────────
const vtData = $node['VirusTotal Lookup'].json;
const malicious  = vtData?.data?.attributes?.last_analysis_stats?.malicious  || 0;
const suspicious = vtData?.data?.attributes?.last_analysis_stats?.suspicious || 0;
const riskFlag = malicious > 5 ? 'CONFIRMED_MALICIOUS' : (malicious > 0 || suspicious > 3) ? 'SUSPICIOUS' : 'CLEAN';
const input = $input.all()[0]?.json || {};
return [{ json: { ...input, ioc_risk_flag: riskFlag, vt_malicious: malicious, vt_suspicious: suspicious } }];

// ── MERGE ALL INTEL SOURCES ─────────────────────────────────────────
// Uses $input.all() to collect items from ALL upstream branches.
// Each parser stamps its output with a 'source' field for identification.

const allItems = $input.all().map(i => i.json).filter(Boolean);

const victims   = allItems.filter(i => i.source === 'ransomware.live');
const groupData = allItems.find(i  => i.source === 'ransomware.live/groups') || {};
const kevData   = allItems.find(i  => i.source === 'CISA KEV')               || {};
const icsData   = allItems.find(i  => i.source === 'CISA ICS Advisories')    || {};
const enriched  = allItems.filter(i => i.ioc_risk_flag !== undefined);

// Baseline trend
const current  = victims.length;
const prior    = parseInt($vars.PRIOR_OT_VICTIM_COUNT || '0') || Math.max(1, Math.floor(current * 0.78));
const deltaPct = ((current - prior) / prior * 100).toFixed(1);
const trend    = current > prior ? 'INCREASING' : current < prior ? 'DECREASING' : 'STABLE';

// Top groups by victim count
const groupCounts = {};
victims.forEach(v => { const g = v.group || 'Unknown'; groupCounts[g] = (groupCounts[g] || 0) + 1; });
const topGroups = Object.entries(groupCounts).sort((a,b)=>b[1]-a[1]).slice(0,8)
  .map(([name, victim_count]) => ({ name, victim_count }));

// Top countries
const countryCounts = {};
victims.forEach(v => { const c = v.country || 'Unknown'; countryCounts[c] = (countryCounts[c] || 0) + 1; });
const topCountries = Object.entries(countryCounts).sort((a,b)=>b[1]-a[1]).slice(0,8)
  .map(([country, count]) => ({ country, count }));

const confirmedMalicious = enriched.filter(e => e.ioc_risk_flag === 'CONFIRMED_MALICIOUS').length;
const suspicious         = enriched.filter(e => e.ioc_risk_flag === 'SUSPICIOUS').length;

return [{ json: {
  generated_at: new Date().toUTCString(),
  ransomware: {
    victim_count_current: current,
    victim_count_prior:   prior,
    delta_pct:            deltaPct,
    trend,
    top_groups:           topGroups,
    top_countries:        topCountries,
    recent_victims:       victims.slice(0, 15),
    ttps:                 (groupData.ttps   || []).slice(0, 40),
    tools:                (groupData.tools  || []).slice(0, 30),
    active_groups:        (groupData.groups || [])
  },
  cisa_kev: {
    total_ics_kevs:       kevData.total_ics_kevs       || 0,
    ransomware_exploited: kevData.ransomware_used_count || 0,
    recent_kevs:          (kevData.recent_kevs          || []).slice(0, 15)
  },
  ics_advisories: {
    total:       icsData.total_advisories || 0,
    ot_relevant: icsData.ot_relevant_count || 0,
    recent:      (icsData.ot_advisories || icsData.advisories || []).slice(0, 10)
  },
  ioc_enrichment: {
    iocs_checked:        enriched.length,
    confirmed_malicious: confirmedMalicious,
    suspicious,
    details:             enriched
  }
}}];

