// ── OUTPUT ENHANCED HTML (v300) ──────────────────────────────────────
const items = $input.all();
const d = items[0]?.json || {};
const ai = d.output || d;

const execSummary     = ai.executive_summary        || 'Analysis pending.';
const threatLevel     = (ai.threat_level             || 'UNKNOWN').toUpperCase();
const confidence      = ai.confidence_score          ?? 0;
const keyFindings     = Array.isArray(ai.key_findings)        ? ai.key_findings        : [];
const ttps            = Array.isArray(ai.ttps)                ? ai.ttps                : [];
const otRisks         = ai.ot_specific_risks         || {};
const threatActors    = Array.isArray(ai.threat_actors)       ? ai.threat_actors       : [];
const vulnSpotlight   = Array.isArray(ai.vulnerability_spotlight) ? ai.vulnerability_spotlight : [];
const iocSummary      = ai.ioc_summary               || {};
const targeting       = ai.targeting_patterns        || {};
const opIntel         = ai.operational_intelligence  || 'No operational intelligence available.';
const recommendations = Array.isArray(ai.recommendations)     ? ai.recommendations     : [];
const negotiation     = ai.negotiation_intel         || {};

const reportId  = `OT-RIB-${new Date().toISOString().replace(/[^0-9]/g,'').slice(0,14)}`;
const timestamp = new Date().toUTCString();

const tc = { CRITICAL:'#dc2626', HIGH:'#ea580c', MEDIUM:'#d97706', LOW:'#16a34a', UNKNOWN:'#6b7280' }[threatLevel] || '#6b7280';
const sc = s => ({ critical:'#dc2626', high:'#ea580c', medium:'#d97706', low:'#16a34a' }[(s||'').toLowerCase()] || '#6b7280');
const ec = e => ({ low:'#16a34a', medium:'#d97706', high:'#dc2626' }[(e||'').toLowerCase()] || '#6b7280');
const tags = (arr, cls='tag') => Array.isArray(arr) && arr.length ? arr.map(v=>`<span class="${cls}">${v}</span>`).join('') : '<span class="muted">None identified</span>';
const iocList = (arr, cls) => Array.isArray(arr) && arr.length ? arr.map(v=>`<li class="ioc-item ${cls}">${v}</li>`).join('') : '<li class="muted-li">None identified</li>';

const ttpRows = ttps.slice(0,12).map(t=>`<tr>
  <td><span class="badge-mitre">${t.mitre_id||'—'}</span></td>
  <td>${t.tactic||'—'}</td><td>${t.technique||'—'}</td>
  <td><span class="ics-stage">${t.ics_kill_chain_stage||'—'}</span></td>
  <td><span class="sev-badge" style="background:${sc(t.severity)}22;color:${sc(t.severity)};border:1px solid ${sc(t.severity)}44">${t.severity||'—'}</span></td>
  <td class="small-text">${t.ot_relevance||'—'}</td></tr>`).join('') || '<tr><td colspan="6" class="empty-row">No TTPs extracted</td></tr>';

const actorRows = threatActors.slice(0,8).map(a=>`<tr>
  <td><strong>${a.name||'—'}</strong></td>
  <td><span class="motivation-badge mot-${(a.motivation||'').toLowerCase().replace(/[^a-z]/g,'')}">${a.motivation||'—'}</span></td>
  <td>${a.ot_capability||'—'}</td>
  <td>${a.energy_sector_focus ? '⚡ Yes' : '—'}</td>
  <td class="small-text">${a.recent_activity||'—'}</td></tr>`).join('') || '<tr><td colspan="5" class="empty-row">No actors identified</td></tr>';

const vulnRows = vulnSpotlight.slice(0,8).map(v=>`<tr>
  <td><a href="https://nvd.nist.gov/vuln/detail/${v.cve_id||''}" target="_blank" class="cve-link">${v.cve_id||'—'}</a></td>
  <td>${v.vendor||'—'}</td><td>${v.product||'—'}</td>
  <td><span class="sev-badge" style="background:${sc(v.severity)}22;color:${sc(v.severity)};border:1px solid ${sc(v.severity)}44">${v.severity||'—'}</span></td>
  <td>${v.exploited_in_wild ? '<span style="color:#ef4444;font-weight:600">⚠ Active</span>' : '—'}</td>
  <td><span class="patch-${(v.patch_priority||'monitor').toLowerCase().replace(/ /g,'-')}">${v.patch_priority||'—'}</span></td>
  <td class="small-text">${v.ot_impact||'—'}</td></tr>`).join('') || '<tr><td colspan="7" class="empty-row">No vulnerabilities highlighted</td></tr>';

const recRows = recommendations.slice(0,8).sort((a,b)=>(a.priority||9)-(b.priority||9)).map(r=>`<tr>
  <td><span class="priority-pill">P${r.priority||'—'}</span></td>
  <td>${r.action||'—'}</td>
  <td class="small-text">${r.rationale||'—'}</td>
  <td><span class="badge-mitre">${r.mitre_addresses||'—'}</span></td>
  <td style="color:${ec(r.effort)}">${r.effort||'—'}</td>
  <td>${r.ot_safe ? '<span style="color:#22c55e;font-weight:600">✓ Safe</span>' : '<span style="color:#f97316;font-weight:600">⚠ Plan</span>'}</td></tr>`).join('') || '<tr><td colspan="6" class="empty-row">No recommendations generated</td></tr>';

const findingsHTML = keyFindings.slice(0,6).map((f,i)=>`<div class="finding-item"><span class="finding-num">${i+1}</span><span>${f}</span></div>`).join('');

const purdueMap = [
  { key:'l0', label:'L0 — Field Devices', desc:'Sensors, actuators, PLCs' },
  { key:'l1', label:'L1 — Control', desc:'PLCs, RTUs, controllers' },
  { key:'l2', label:'L2 — Supervisory', desc:'SCADA, HMI, DCS' },
  { key:'l3', label:'L3 — Operations', desc:'Historians, MES' },
  { key:'l4', label:'L4 — Enterprise', desc:'IT/OT boundary, DMZ' }
];
const targeted = (otRisks.purdue_levels_targeted || []).map(l => l.toLowerCase());
const purdueHTML = purdueMap.map(({key, label, desc}) => {
  const hit = targeted.some(t => t.includes(key) || t.includes(key.replace('l','level ')));
  return `<div class="purdue-level ${hit ? 'purdue-hit' : 'purdue-ok'}"><div><strong>${label}</strong> <span class="purdue-desc">${desc}</span></div>${hit ? '<span class="purdue-flag">🎯 TARGETED</span>' : ''}</div>`;
}).join('');

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8"/>
<meta name="viewport" content="width=device-width,initial-scale=1"/>
<title>OT Intelligence Brief — ${reportId}</title>
<style>
:root{--bg:#0a0f1e;--surface:#111827;--s2:#1a2332;--s3:#1f2d42;--border:#1e3a5f;--text:#e2e8f0;--muted:#64748b;--accent:#38bdf8;--accent2:#818cf8;--font:'Segoe UI',system-ui,sans-serif;}
*{box-sizing:border-box;margin:0;padding:0;}
body{background:var(--bg);color:var(--text);font-family:var(--font);font-size:13.5px;line-height:1.65;}
a{color:var(--accent);text-decoration:none;} a:hover{text-decoration:underline;}
.page{max-width:1200px;margin:0 auto;padding:32px 24px 72px;}
.header{display:flex;align-items:flex-start;justify-content:space-between;flex-wrap:wrap;gap:20px;padding-bottom:24px;margin-bottom:28px;border-bottom:1px solid var(--border);}
.brand{display:flex;align-items:center;gap:12px;margin-bottom:8px;}
.brand-icon{width:38px;height:38px;background:linear-gradient(135deg,#dc2626,#7c3aed);border-radius:8px;display:flex;align-items:center;justify-content:center;font-size:20px;}
.header-title{font-size:20px;font-weight:700;color:#fff;}
.header-sub{font-size:11px;color:var(--muted);margin-top:3px;}
.header-right{display:flex;gap:14px;align-items:center;flex-wrap:wrap;}
.threat-pill{padding:8px 20px;border-radius:8px;font-weight:700;font-size:14px;background:${tc}18;border:1.5px solid ${tc}55;color:${tc};letter-spacing:.5px;}
.conf-wrap{text-align:center;}
.conf-label{font-size:10px;color:var(--muted);text-transform:uppercase;letter-spacing:.6px;margin-bottom:4px;}
.conf-ring{width:68px;height:68px;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:800;color:#fff;background:conic-gradient(${tc} ${confidence}%, var(--s2) 0);}
.tlp-bar{display:flex;gap:8px;align-items:center;background:#7f1d1d22;border:1px solid #7f1d1d44;border-radius:6px;padding:6px 14px;font-size:11px;color:#fca5a5;font-weight:600;}
.stat-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(155px,1fr));gap:14px;margin-bottom:24px;}
.stat-card{background:var(--surface);border:1px solid var(--border);border-radius:10px;padding:16px 18px;}
.stat-label{font-size:10px;text-transform:uppercase;letter-spacing:.7px;color:var(--muted);margin-bottom:6px;}
.stat-value{font-size:26px;font-weight:800;line-height:1;}
.stat-sub{font-size:11px;color:var(--muted);margin-top:5px;}
.exec-box{background:linear-gradient(135deg,var(--s2),var(--s3));border:1px solid var(--border);border-left:3px solid var(--accent);border-radius:0 10px 10px 0;padding:18px 22px;margin-bottom:20px;font-size:14px;line-height:1.75;}
.findings-grid{display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-top:16px;}
.finding-item{display:flex;gap:12px;align-items:flex-start;background:var(--surface);border:1px solid var(--border);border-radius:8px;padding:12px 14px;}
.finding-num{width:22px;height:22px;min-width:22px;background:var(--accent);color:#0a0f1e;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:11px;font-weight:800;margin-top:1px;}
.section{background:var(--surface);border:1px solid var(--border);border-radius:10px;margin-bottom:20px;overflow:hidden;}
.section-hdr{display:flex;align-items:center;gap:10px;padding:12px 20px;border-bottom:1px solid var(--border);background:var(--s2);font-size:11px;font-weight:700;text-transform:uppercase;letter-spacing:.8px;color:var(--accent);}
.section-body{padding:18px 20px;}
.no-pad{padding:0;}
table{width:100%;border-collapse:collapse;font-size:12.5px;}
th{text-align:left;padding:9px 12px;background:var(--s2);color:var(--muted);font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;}
td{padding:9px 12px;border-top:1px solid var(--border);vertical-align:top;}
tr:hover td{background:var(--s2);}
.empty-row{text-align:center;color:var(--muted);font-style:italic;padding:20px;}
.small-text{font-size:11.5px;color:#94a3b8;max-width:220px;}
.badge-mitre{display:inline-block;padding:2px 7px;border-radius:4px;font-size:10.5px;font-weight:700;background:#1e3a5f;color:#93c5fd;border:1px solid #2563eb33;}
.sev-badge{display:inline-block;padding:2px 8px;border-radius:4px;font-size:10.5px;font-weight:700;}
.ics-stage{display:inline-block;padding:2px 7px;border-radius:4px;font-size:10.5px;background:#2d1b6933;color:#c4b5fd;border:1px solid #7c3aed33;}
.priority-pill{display:inline-block;padding:3px 8px;border-radius:4px;font-size:11px;font-weight:800;background:var(--s2);border:1px solid var(--border);color:var(--accent);}
.motivation-badge{display:inline-block;padding:2px 8px;border-radius:4px;font-size:10.5px;font-weight:600;}
.mot-financial{background:#78350f33;color:#fcd34d;} .mot-espionage{background:#1e3a5f33;color:#93c5fd;}
.mot-destructive{background:#7f1d1d33;color:#fca5a5;} .mot-hacktivism{background:#14532d33;color:#86efac;}
.patch-immediate{background:#7f1d1d33;color:#fca5a5;padding:2px 8px;border-radius:4px;font-size:10.5px;font-weight:700;border:1px solid #dc262644;}
.patch-high{background:#7c2d1233;color:#fdba74;padding:2px 8px;border-radius:4px;font-size:10.5px;font-weight:700;border:1px solid #ea580c44;}
.patch-medium{background:#78350f33;color:#fcd34d;padding:2px 8px;border-radius:4px;font-size:10.5px;font-weight:700;border:1px solid #d9780644;}
.patch-monitor{background:#14532d33;color:#86efac;padding:2px 8px;border-radius:4px;font-size:10.5px;font-weight:700;border:1px solid #16a34a44;}
.cve-link{color:var(--accent2);font-family:monospace;font-size:11.5px;}
.tag{display:inline-block;background:#1e3a5f;color:#93c5fd;border-radius:4px;padding:2px 8px;font-size:11.5px;margin:2px;}
.tag-region{background:#2d1b69;color:#c4b5fd;}
.muted{color:var(--muted);font-style:italic;} .muted-li{color:var(--muted);font-style:italic;list-style:none;}
.ioc-cols{display:grid;grid-template-columns:repeat(auto-fit,minmax(220px,1fr));gap:18px;}
.ioc-group h4{font-size:10px;text-transform:uppercase;letter-spacing:.6px;color:var(--muted);margin-bottom:8px;}
.ioc-group ul{list-style:none;}
.ioc-item{font-family:'Courier New',monospace;font-size:11.5px;padding:4px 10px;background:var(--s2);border-radius:4px;margin-bottom:4px;word-break:break-all;}
.ioc-domain{border-left:3px solid #ef4444;} .ioc-ip{border-left:3px solid #f97316;} .ioc-hash{border-left:3px solid #8b5cf6;} .ioc-btc{border-left:3px solid #eab308;}
.enrich-bar{display:flex;gap:14px;flex-wrap:wrap;margin-bottom:18px;}
.enrich-item{display:flex;align-items:center;gap:8px;background:var(--s2);border:1px solid var(--border);border-radius:6px;padding:8px 14px;font-size:12.5px;}
.enrich-dot{width:9px;height:9px;border-radius:50%;flex-shrink:0;}
.purdue-stack{display:flex;flex-direction:column;gap:6px;}
.purdue-level{display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:8px;border-radius:8px;padding:12px 16px;border:1px solid var(--border);}
.purdue-ok{background:var(--s2);} .purdue-hit{background:#7f1d1d18;border-color:#dc262644;}
.purdue-desc{font-size:11.5px;color:var(--muted);margin-left:6px;}
.purdue-flag{font-size:11px;font-weight:700;color:#ef4444;background:#7f1d1d33;border:1px solid #dc262644;border-radius:4px;padding:2px 8px;}
.ot-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;}
.ot-card{background:var(--s2);border:1px solid var(--border);border-radius:8px;padding:14px;}
.ot-card-label{font-size:10px;text-transform:uppercase;letter-spacing:.6px;color:var(--muted);margin-bottom:8px;}
.ot-card-value{font-size:13px;line-height:1.6;}
.op-intel{background:var(--s2);border-left:3px solid var(--accent2);border-radius:0 8px 8px 0;padding:16px 20px;font-size:13px;line-height:1.75;white-space:pre-wrap;}
.two-col{display:grid;grid-template-columns:1fr 1fr;gap:20px;margin-bottom:20px;}
.neg-grid{display:grid;grid-template-columns:repeat(auto-fit,minmax(170px,1fr));gap:12px;}
.neg-card{background:var(--s2);border-radius:8px;padding:14px;border:1px solid var(--border);}
.neg-label{font-size:10px;text-transform:uppercase;letter-spacing:.6px;color:var(--muted);margin-bottom:6px;}
.neg-value{font-size:13px;font-weight:600;}
.footer{margin-top:48px;padding-top:16px;border-top:1px solid var(--border);display:flex;justify-content:space-between;flex-wrap:wrap;gap:8px;font-size:10.5px;color:var(--muted);}
@media(max-width:700px){.two-col,.ot-grid,.findings-grid{grid-template-columns:1fr;}.header{flex-direction:column;}}
@media print{body{background:#fff;color:#000;}.section,.stat-card{border:1px solid #ccc;}}
</style>
</head>
<body>
<div class="page">

<div class="header">
  <div>
    <div class="brand"><div class="brand-icon">⚡</div><div><div class="header-title">OT & Ransomware Intelligence Brief</div><div class="header-sub">Energy Sector Focus &nbsp;·&nbsp; ${reportId} &nbsp;·&nbsp; ${timestamp}</div></div></div>
    <div class="tlp-bar">🔴 TLP:AMBER &nbsp;|&nbsp; CONFIDENTIAL &nbsp;|&nbsp; Distribute within organisation only</div>
  </div>
  <div class="header-right">
    <div class="threat-pill">${threatLevel} THREAT</div>
    <div class="conf-wrap"><div class="conf-label">Confidence</div><div class="conf-ring">${confidence}%</div></div>
  </div>
</div>

<div class="stat-grid">
  <div class="stat-card"><div class="stat-label">OT/Energy Victims</div><div class="stat-value" style="color:${tc}">${d.ransomware?.victim_count_current ?? ai.ransomware?.victim_count_current ?? '—'}</div><div class="stat-sub">Current period</div></div>
  <div class="stat-card"><div class="stat-label">Period Trend</div><div class="stat-value" style="color:${ (d.ransomware?.trend||'') === 'INCREASING' ? '#ef4444' : (d.ransomware?.trend||'') === 'DECREASING' ? '#22c55e' : '#f97316'}">${ (d.ransomware?.trend||'') === 'INCREASING' ? '▲' : (d.ransomware?.trend||'') === 'DECREASING' ? '▼' : '●'} ${d.ransomware?.delta_pct ?? '0'}%</div><div class="stat-sub">${d.ransomware?.trend || 'STABLE'}</div></div>
  <div class="stat-card"><div class="stat-label">ICS CVEs (KEV)</div><div class="stat-value" style="color:#f97316">${d.cisa_kev?.total_ics_kevs ?? '—'}</div><div class="stat-sub">${d.cisa_kev?.ransomware_exploited ?? 0} ransomware-exploited</div></div>
  <div class="stat-card"><div class="stat-label">ICS Advisories</div><div class="stat-value" style="color:#818cf8">${d.ics_advisories?.total ?? '—'}</div><div class="stat-sub">${d.ics_advisories?.ot_relevant ?? 0} OT/Energy relevant</div></div>
  <div class="stat-card"><div class="stat-label">TTPs Mapped</div><div class="stat-value">${ttps.length}</div><div class="stat-sub">ICS Kill Chain aligned</div></div>
  <div class="stat-card"><div class="stat-label">Threat Actors</div><div class="stat-value">${threatActors.length}</div><div class="stat-sub">${threatActors.filter(a=>a.energy_sector_focus).length} energy-focused</div></div>
</div>

<div class="section"><div class="section-hdr"><span>📋</span> Executive Summary</div><div class="section-body"><div class="exec-box">${execSummary}</div>${findingsHTML ? `<div style="font-size:10px;text-transform:uppercase;letter-spacing:.7px;color:var(--muted);margin-bottom:10px;font-weight:700">KEY FINDINGS</div><div class="findings-grid">${findingsHTML}</div>` : ''}</div></div>

<div class="two-col">
  <div class="section" style="margin-bottom:0"><div class="section-hdr"><span>🏭</span> OT/ICS Risk Profile</div><div class="section-body"><div class="ot-grid">
    <div class="ot-card"><div class="ot-card-label">Protocols at Risk</div><div class="ot-card-value">${tags(otRisks.protocols_at_risk)}</div></div>
    <div class="ot-card"><div class="ot-card-label">Affected ICS Vendors</div><div class="ot-card-value">${tags(otRisks.affected_vendors)}</div></div>
    <div class="ot-card" style="grid-column:1/-1"><div class="ot-card-label">Physical Impact Potential</div><div class="ot-card-value" style="color:#fca5a5">${otRisks.physical_impact_potential||'—'}</div></div>
    <div class="ot-card" style="grid-column:1/-1"><div class="ot-card-label">IT/OT Convergence Risk</div><div class="ot-card-value">${otRisks.it_ot_convergence_risk||'—'}</div></div>
  </div></div></div>
  <div class="section" style="margin-bottom:0"><div class="section-hdr"><span>📐</span> Purdue Model — Targeted Levels</div><div class="section-body"><div class="purdue-stack">${purdueHTML}</div></div></div>
</div>

<div class="section"><div class="section-hdr"><span>👤</span> Threat Actor Assessment</div><div class="section-body no-pad"><table><thead><tr><th>Actor</th><th>Motivation</th><th>OT Capability</th><th>Energy Focus</th><th>Recent Activity</th></tr></thead><tbody>${actorRows}</tbody></table></div></div>

<div class="section"><div class="section-hdr"><span>🛠</span> TTPs — MITRE ATT&CK for ICS</div><div class="section-body no-pad"><table><thead><tr><th>ID</th><th>Tactic</th><th>Technique</th><th>ICS Kill Chain</th><th>Severity</th><th>OT Relevance</th></tr></thead><tbody>${ttpRows}</tbody></table></div></div>

<div class="section"><div class="section-hdr"><span>🔓</span> ICS Vulnerability Spotlight — CISA KEV</div><div class="section-body no-pad"><table><thead><tr><th>CVE</th><th>Vendor</th><th>Product</th><th>Severity</th><th>Exploited</th><th>Patch Priority</th><th>OT Impact</th></tr></thead><tbody>${vulnRows}</tbody></table></div></div>

<div class="section"><div class="section-hdr"><span>🔬</span> IOC Enrichment — VirusTotal + AbuseIPDB</div><div class="section-body">
  <div class="enrich-bar">
    <div class="enrich-item"><div class="enrich-dot" style="background:#ef4444"></div>Confirmed Malicious: <strong>${iocSummary.malicious_domains?.length||0}</strong></div>
    <div class="enrich-item"><div class="enrich-dot" style="background:#f97316"></div>Suspicious IPs: <strong>${iocSummary.suspicious_ips?.length||0}</strong></div>
    <div class="enrich-item"><div class="enrich-dot" style="background:#8b5cf6"></div>File Hashes: <strong>${iocSummary.file_hashes?.length||0}</strong></div>
    <div class="enrich-item"><div class="enrich-dot" style="background:#eab308"></div>BTC Addresses: <strong>${iocSummary.btc_addresses?.length||0}</strong></div>
  </div>
  <div class="ioc-cols">
    <div class="ioc-group"><h4>Malicious Domains</h4><ul>${iocList(iocSummary.malicious_domains,'ioc-domain')}</ul></div>
    <div class="ioc-group"><h4>Suspicious IPs</h4><ul>${iocList(iocSummary.suspicious_ips,'ioc-ip')}</ul></div>
    <div class="ioc-group"><h4>File Hashes</h4><ul>${iocList(iocSummary.file_hashes,'ioc-hash')}</ul></div>
    <div class="ioc-group"><h4>BTC Addresses</h4><ul>${iocList(iocSummary.btc_addresses,'ioc-btc')}</ul></div>
  </div>
</div></div>

<div class="two-col">
  <div class="section" style="margin-bottom:0"><div class="section-hdr"><span>🎯</span> Targeting Patterns</div><div class="section-body"><table>
    <tr><td style="width:130px;color:var(--muted);font-size:11px">Primary Sectors</td><td>${tags(targeting.primary_sectors)}</td></tr>
    <tr><td style="color:var(--muted);font-size:11px">Top Regions</td><td>${tags(targeting.top_regions,'tag tag-region')}</td></tr>
    <tr><td style="color:var(--muted);font-size:11px">Victim Profile</td><td style="font-size:12.5px">${targeting.victim_profile||'—'}</td></tr>
    <tr><td style="color:var(--muted);font-size:11px">Attack Vectors</td><td style="font-size:12.5px">${targeting.attack_vector_preference||'—'}</td></tr>
  </table></div></div>
  <div class="section" style="margin-bottom:0"><div class="section-hdr"><span>💰</span> Negotiation Intelligence</div><div class="section-body"><div class="neg-grid">
    <div class="neg-card"><div class="neg-label">Demand Range</div><div class="neg-value">${negotiation.typical_demand_range||'—'}</div></div>
    <div class="neg-card"><div class="neg-label">Payment Methods</div><div class="neg-value" style="font-weight:400">${(negotiation.payment_methods||[]).join(', ')||'—'}</div></div>
    <div class="neg-card"><div class="neg-label">Decryptor Reliability</div><div class="neg-value">${negotiation.decryptor_reliability||'—'}</div></div>
    <div class="neg-card" style="grid-column:1/-1"><div class="neg-label">Recommendation</div><div class="neg-value" style="font-weight:400;font-size:12.5px">${negotiation.recommendation||'—'}</div></div>
  </div></div></div>
</div>

<div class="section"><div class="section-hdr"><span>📡</span> Operational Intelligence Narrative</div><div class="section-body"><div class="op-intel">${opIntel}</div></div></div>

<div class="section"><div class="section-hdr"><span>✅</span> Prioritised Recommendations</div><div class="section-body no-pad"><table><thead><tr><th>Priority</th><th>Action</th><th>Rationale</th><th>MITRE</th><th>Effort</th><th>OT Safe?</th></tr></thead><tbody>${recRows}</tbody></table></div></div>

<div class="footer">
  <span>Report ID: ${reportId}</span>
  <span>Generated: ${timestamp}</span>
  <span>Sources: ransomware.live · CISA KEV · CISA ICS Advisories · VirusTotal · AbuseIPDB · Claude AI</span>
  <span>🔴 TLP:AMBER — Not for public release</span>
</div>
</div>
</body>
</html>`;

const buf = Buffer.from(html, 'utf-8');
const ts  = new Date().toISOString().replace(/[:.]/g,'-').slice(0,19);
const fileName = `OT_Intel_Brief_${ts}.html`;

return [{
  json: {
    html, report_id: reportId, status: 'html_generated', fileName,
    threat_level: threatLevel, confidence,
    markdown: `# OT Intelligence Brief\n**Report:** ${reportId}\n**Threat Level:** ${threatLevel} | **Confidence:** ${confidence}%\n\n${execSummary}\n\n**Key Findings:**\n${keyFindings.map((f,i)=>`${i+1}. ${f}`).join('\n')}\n\n_Full report attached._`,
    slack_text: `:rotating_light: *OT Intel Brief* | ${reportId}\n*Threat Level:* ${threatLevel} | *Confidence:* ${confidence}%\n\n*Key Findings:*\n${keyFindings.slice(0,3).map((f,i)=>`${i+1}. ${f}`).join('\n')}\n\n*TTPs:* ${ttps.length} | *Actors:* ${threatActors.length} | *ICS CVEs:* ${d.cisa_kev?.total_ics_kevs||0}\n_Full HTML report attached_`
  },
  binary: { data: { data: buf.toString('base64'), mimeType: 'text/html', fileName } }
}];

const items = $input.all();
const d = items[0]?.json || {};
const html = d.html || '<html><body><p>No HTML generated.</p></body></html>';
const fileName = d.fileName || `OT_Intel_Brief_${new Date().toISOString().slice(0,10)}.html`;
const buf = Buffer.from(html, 'utf-8');
return [{ json: { status: 'file_ready', fileName }, binary: { data: { data: buf.toString('base64'), mimeType: 'text/html', fileName } } }];
